import{_ as a,c as e,o as l,V as i}from"./chunks/framework.9b555ede.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"note/Web性能优化实践.md","filePath":"note/Web性能优化实践.md","lastUpdated":1645753949000}'),t={name:"note/Web性能优化实践.md"},s=i(`<p>关于前端性能问题，我们可以大体上分三类进行说明。</p><h2 id="_1-网络请求-资源加载问题" tabindex="-1">1. 网络请求，资源加载问题 <a class="header-anchor" href="#_1-网络请求-资源加载问题" aria-label="Permalink to &quot;1. 网络请求，资源加载问题&quot;">​</a></h2><p>在我们日常开发中，最常遇到的就是网络请求慢带来的页面性能问题。</p><p>静态资源问题，需要从构建、打包、部署角度出发，减小资源大小，合理利用缓存，CDN 多点内容分发。</p><p>数据接口问题，需要我们前端人员及时找中后台开发进行协商，更合理的调用数据接口。</p><ul><li>静态资源采用 CDN 加速</li><li>首屏加载，非必要资源懒加载，第三方模块按需加载，tree shaking</li><li>资源加载过程中，友好提示，骨架屏等措施</li><li>数据量大时，切片加载</li><li>多个数据接口合并，合理使用同步异步接口顺序</li><li>项目打包，减小单文件的大小，通常小于 500kb，视情况做调整</li><li>资源压缩，合理拆分与合并</li><li>所用域名尽可能统一，减少 DNS 解析，一个域名一次最多发出 6 个请求，PC 端 2-4 个，移动端最好 2 个，因为移动端的 DNS 解析比较慢</li></ul><h2 id="_2-浏览器渲染-交互问题" tabindex="-1">2. 浏览器渲染，交互问题 <a class="header-anchor" href="#_2-浏览器渲染-交互问题" aria-label="Permalink to &quot;2. 浏览器渲染，交互问题&quot;">​</a></h2><p>这类的问题，主流框架层次已经帮我们优化很多了</p><ul><li>虚拟 DOM，减少频繁直接操作 DOM 的开销</li><li>核心样式提前加载，减少浏览器回流重排</li><li>交互事件集中处理，避免冗余事件的触发调用</li></ul><h2 id="_3-规范编码-编码技巧问题" tabindex="-1">3. 规范编码，编码技巧问题 <a class="header-anchor" href="#_3-规范编码-编码技巧问题" aria-label="Permalink to &quot;3. 规范编码，编码技巧问题&quot;">​</a></h2><ul><li>vue 中，处理大数据量表格数据时，可使用 Object.freeze() 进行优化，由于每次更新数据都是全量替换，因此我们没必要对每个数据的属性进行依赖追踪，采用 Object.freeze()可以冻结该数组对象，防止 vue 对其进行响应式改造。</li><li>及时销毁，当我们声明了一些定时器、监听器、DOM 对象时，应在合适的时机进行销毁操作，减少资源的占用</li><li>合理使用数组函数，减少遍历次数，注意哪些是改变原数组的，哪些又会生成新的数组</li></ul><h2 id="代码规范-风格统一-简洁大方" tabindex="-1">代码规范，风格统一，简洁大方 <a class="header-anchor" href="#代码规范-风格统一-简洁大方" aria-label="Permalink to &quot;代码规范，风格统一，简洁大方&quot;">​</a></h2><ul><li>通用的 css,js 合并，小文件合并，减少请求并发数，同时也要注意拆分过大文件</li><li>style 要合理运用，优先考虑可维护性</li></ul><h2 id="利用-google-开发者工具的-coverage-查看无用的代码" tabindex="-1">利用 Google 开发者工具的 Coverage 查看无用的代码 <a class="header-anchor" href="#利用-google-开发者工具的-coverage-查看无用的代码" aria-label="Permalink to &quot;利用 Google 开发者工具的 Coverage 查看无用的代码&quot;">​</a></h2><h2 id="用-css-替换图片" tabindex="-1">用 CSS 替换图片 <a class="header-anchor" href="#用-css-替换图片" aria-label="Permalink to &quot;用 CSS 替换图片&quot;">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">img {</span></span>
<span class="line"><span style="color:#A6ACCD;">    -webkit-filter: grayscale(100%);</span></span>
<span class="line"><span style="color:#A6ACCD;">    /* old safari */</span></span>
<span class="line"><span style="color:#A6ACCD;">    filter: grayscale(100%);</span></span>
<span class="line"><span style="color:#A6ACCD;">}</span></span></code></pre></div><h2 id="精灵图的使用" tabindex="-1">精灵图的使用 <a class="header-anchor" href="#精灵图的使用" aria-label="Permalink to &quot;精灵图的使用&quot;">​</a></h2><h2 id="gzip-压缩" tabindex="-1">gzip 压缩 <a class="header-anchor" href="#gzip-压缩" aria-label="Permalink to &quot;gzip 压缩&quot;">​</a></h2><h2 id="减少-http-请求次数-dns-查询次数" tabindex="-1">减少 HTTP 请求次数，DNS 查询次数 <a class="header-anchor" href="#减少-http-请求次数-dns-查询次数" aria-label="Permalink to &quot;减少 HTTP 请求次数，DNS 查询次数&quot;">​</a></h2><h2 id="加载顺序" tabindex="-1">加载顺序 <a class="header-anchor" href="#加载顺序" aria-label="Permalink to &quot;加载顺序&quot;">​</a></h2><ul><li>将 CSS 放在 HEAD 中</li><li>将外部脚本置底</li></ul><h2 id="http-缓存过期时间" tabindex="-1">HTTP 缓存过期时间 <a class="header-anchor" href="#http-缓存过期时间" aria-label="Permalink to &quot;HTTP 缓存过期时间&quot;">​</a></h2><ul><li>不同文件使用不同的缓存策略</li></ul><h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h2>`,24),o=[s];function r(n,h,c,d,p,u){return l(),e("div",null,o)}const f=a(t,[["render",r]]);export{b as __pageData,f as default};
